const items = $input.all();

function get(obj, path, fallback = "") {
  try {
    return path.split(".").reduce((acc, part) => acc?.[part], obj) ?? fallback;
  } catch (e) {
    return fallback;
  }
}

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function normalizePriority(priority) {
  const value = clean(priority).toLowerCase();

  if (["highest", "critical", "critique", "blocker", "bloquante"].some(v => value.includes(v))) {
    return "Critique";
  }

  if (["high", "haute", "major", "majeure"].some(v => value.includes(v))) {
    return "Haute";
  }

  if (["medium", "moyenne", "normal"].some(v => value.includes(v))) {
    return "Moyenne";
  }

  if (["low", "basse", "mineure"].some(v => value.includes(v))) {
    return "Basse";
  }

  return priority || "Non définie";
}

function detectBlocked(fields) {
  const status = clean(get(fields, "status.name")).toLowerCase();
  const labels = Array.isArray(fields.labels) ? fields.labels.join(" ").toLowerCase() : "";
  const summary = clean(fields.summary).toLowerCase();

  const blockerText = [
    status,
    labels,
    summary
  ].join(" ");

  return (
    blockerText.includes("bloqu") ||
    blockerText.includes("blocked") ||
    blockerText.includes("blocker") ||
    blockerText.includes("en attente") ||
    blockerText.includes("waiting")
  );
}

function detectBlockerType(fields) {
  const labels = Array.isArray(fields.labels) ? fields.labels.join(" ").toLowerCase() : "";
  const summary = clean(fields.summary).toLowerCase();
  const status = clean(get(fields, "status.name")).toLowerCase();

  const text = `${labels} ${summary} ${status}`;

  if (text.includes("review") || text.includes("validation") || text.includes("pr")) {
    return "Validation";
  }

  if (text.includes("api") || text.includes("bug") || text.includes("tech") || text.includes("dev")) {
    return "Technique";
  }

  if (text.includes("client") || text.includes("métier") || text.includes("fonctionnel")) {
    return "Fonctionnel";
  }

  if (text.includes("dépendance") || text.includes("dependency")) {
    return "Dépendance";
  }

  if (text.includes("disponibilité") || text.includes("absence")) {
    return "Disponibilité";
  }

  return "";
}

function extractSprint(fields) {
  // Selon Jira, le sprint peut être dans un champ customfield.
  // Ce code essaie de trouver un champ qui contient le mot sprint.
  for (const [key, value] of Object.entries(fields)) {
    if (!key.toLowerCase().includes("sprint") && !String(key).startsWith("customfield")) {
      continue;
    }

    if (Array.isArray(value) && value.length > 0) {
      const lastSprint = value[value.length - 1];

      if (typeof lastSprint === "object" && lastSprint.name) {
        return lastSprint.name;
      }

      if (typeof lastSprint === "string") {
        const match = lastSprint.match(/name=([^,\]]+)/);
        if (match) return match[1];
        return lastSprint;
      }
    }

    if (value && typeof value === "object" && value.name) {
      return value.name;
    }

    if (typeof value === "string" && value.toLowerCase().includes("sprint")) {
      return value;
    }
  }

  return "";
}

const normalized = [];

for (const item of items) {
  const issue = item.json;
  const fields = issue.fields || issue;

  const key = clean(issue.key || fields.key || issue.id);
  const title = clean(fields.summary || fields.title || fields.name);
  const status = clean(get(fields, "status.name", fields.status));
  const statusCategory = clean(get(fields, "status.statusCategory.name"));
  const assignee = clean(
    get(fields, "assignee.displayName") ||
    get(fields, "assignee.name") ||
    get(fields, "assignee.emailAddress")
  );

  const reporter = clean(
    get(fields, "reporter.displayName") ||
    get(fields, "reporter.emailAddress")
  );

  const priority = normalizePriority(get(fields, "priority.name", fields.priority));
  const createdAt = clean(fields.created);
  const updatedAt = clean(fields.updated);
  const dueDate = clean(fields.duedate || fields.dueDate);
  const labels = Array.isArray(fields.labels) ? fields.labels : [];

  const blocked = detectBlocked(fields);
  const blockerType = detectBlockerType(fields);

  const sprint = extractSprint(fields);

  normalized.push({
    json: {
      source: "jira",
      type: "task",

      external_id: key,
      task_id: key,
      title,

      status,
      status_category: statusCategory,
      assignee,
      reporter,
      priority,

      sprint,
      created_at: createdAt,
      updated_at: updatedAt,
      due_date: dueDate,

      labels,
      blocked,
      blocker_type: blockerType,

      review_status: "",
      ci_status: "",
      linked_pr: "",

      raw_source: "jira",
      source_url: key ? `https://TON-DOMAINE.atlassian.net/browse/${key}` : "",

      normalized_at: new Date().toISOString()
    }
  });
}

return normalized;

const items = $input.all();

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function hoursSince(dateValue) {
  if (!dateValue) return null;
  const date = new Date(dateValue);
  if (isNaN(date.getTime())) return null;
  return Math.floor((Date.now() - date.getTime()) / (1000 * 60 * 60));
}

function detectLinkedTask(text) {
  const value = clean(text);

  const patterns = [
    /([A-Z]+-\d+)/,
    /(US[-_ ]?\d+)/i,
    /(TASK[-_ ]?\d+)/i
  ];

  for (const pattern of patterns) {
    const match = value.match(pattern);
    if (match) return match[1].toUpperCase().replace(" ", "-").replace("_", "-");
  }

  return "";
}

function detectReviewStatus(pr) {
  const requestedReviewers = pr.requested_reviewers || pr.requestedReviewers || [];
  const draft = pr.draft === true;

  if (draft) return "Draft";
  if (Array.isArray(requestedReviewers) && requestedReviewers.length > 0) return "Review demandée";

  return "Aucun reviewer";
}

function detectBlocked(pr, ageHours, reviewStatus) {
  if (pr.draft === true) return false;
  if (reviewStatus === "Aucun reviewer") return true;
  if (ageHours !== null && ageHours >= 24 && reviewStatus === "Review demandée") return true;
  return false;
}

const normalized = [];

for (const item of items) {
  const pr = item.json;

  const number = clean(pr.number || pr.id);
  const title = clean(pr.title);
  const body = clean(pr.body);
  const state = clean(pr.state);
  const author = clean(pr.user?.login || pr.author?.login || pr.user);
  const createdAt = clean(pr.created_at || pr.createdAt);
  const updatedAt = clean(pr.updated_at || pr.updatedAt);
  const mergedAt = clean(pr.merged_at || pr.mergedAt);
  const htmlUrl = clean(pr.html_url || pr.url);

  const reviewers = Array.isArray(pr.requested_reviewers)
    ? pr.requested_reviewers.map(r => r.login || r.name || r).filter(Boolean)
    : [];

  const ageHours = hoursSince(createdAt);
  const reviewStatus = detectReviewStatus(pr);
  const linkedTask = detectLinkedTask(`${title} ${body} ${pr.head?.ref || ""}`);

  // 🔹 Vérification merge non approuvé
  if (mergedAt && !pr.reviews?.some(r => r.state === "APPROVED")) {
    pr.blocked = true;
    pr.blocker_type = "Merge non approuvé";
  }

  // Détection blocage classique
  const blocked = pr.blocked || detectBlocked(pr, ageHours, reviewStatus);

  let blockerType = "";
  if (pr.blocker_type) {
    // Priorité au merge non approuvé si présent
    blockerType = pr.blocker_type;
  } else if (blocked && reviewStatus === "Aucun reviewer") {
    blockerType = "Validation";
  } else if (blocked && reviewStatus === "Review demandée") {
    blockerType = "Review en attente";
  }

  normalized.push({
    json: {
      source: "github",
      type: "pull_request",

      external_id: number ? `GH-PR-${number}` : "",
      pr_id: number,
      task_id: linkedTask,
      linked_task: linkedTask,

      title,
      status: state,
      author,
      assignee: author,
      reviewers,

      created_at: createdAt,
      updated_at: updatedAt,
      merged_at: mergedAt,
      age_hours: ageHours,

      review_status: reviewStatus,
      ci_status: "",

      priority: "",
      sprint: "",
      due_date: "",

      blocked,
      blocker_type: blockerType,

      raw_source: "github",
      source_url: htmlUrl,

      normalized_at: new Date().toISOString()
    }
  });
}

return normalized;

