  const value = clean(text);

  const patterns = [
    /([A-Z]+-\d+)/,
    /(US[-_ ]?\d+)/i,
    /(TASK[-_ ]?\d+)/i
  ];

  for (const pattern of patterns) {
    const match = value.match(pattern);
    if (match) return match[1].toUpperCase().replace(" ", "-").replace("_", "-");
  }

  return "";
}

function detectReviewStatus(mr) {
  const reviewers = mr.reviewers || [];
  const assignees = mr.assignees || [];

  if (mr.draft === true || mr.work_in_progress === true) return "Draft";
  if (Array.isArray(reviewers) && reviewers.length > 0) return "Review demandée";
  if (Array.isArray(assignees) && assignees.length > 0) return "Assignée";

  return "Aucun reviewer";
}

function detectPipelineStatus(mr) {
  if (mr.head_pipeline?.status) return mr.head_pipeline.status;
  if (mr.pipeline?.status) return mr.pipeline.status;
  return "";
}

const normalized = [];

for (const item of items) {
  const mr = item.json;

  const iid = clean(mr.iid || mr.id);
  const title = clean(mr.title);
  const description = clean(mr.description);
  const state = clean(mr.state);
  const author = clean(mr.author?.name || mr.author?.username || mr.author);
  const createdAt = clean(mr.created_at || mr.createdAt);
  const updatedAt = clean(mr.updated_at || mr.updatedAt);
  const mergedAt = clean(mr.merged_at || mr.mergedAt);
  const webUrl = clean(mr.web_url || mr.url);

  const reviewers = Array.isArray(mr.reviewers)
    ? mr.reviewers.map(r => r.name || r.username || r).filter(Boolean)
    : [];

  const ageHours = hoursSince(createdAt);
  const reviewStatus = detectReviewStatus(mr);
  const ciStatus = detectPipelineStatus(mr);
  const linkedTask = detectLinkedTask(`${title} ${description} ${mr.source_branch || ""}`);

  let blocked = false;
  let blockerType = "";

  if (reviewStatus === "Aucun reviewer") {
    blocked = true;
    blockerType = "Validation";
  }

  if (ageHours !== null && ageHours >= 24 && reviewStatus === "Review demandée") {
    blocked = true;
    blockerType = "Review en attente";
  }

  if (ciStatus === "failed") {
    blocked = true;
    blockerType = "CI/CD échouée";
  }

  normalized.push({
    json: {
      source: "gitlab",
      type: "merge_request",

      external_id: iid ? `GL-MR-${iid}` : "",
      mr_id: iid,
      task_id: linkedTask,
      linked_task: linkedTask,

      title,
      status: state,
      author,
      assignee: author,
      reviewers,

      created_at: createdAt,
      updated_at: updatedAt,
      merged_at: mergedAt,
      age_hours: ageHours,

      review_status: reviewStatus,
      ci_status: ciStatus,

      priority: "",
      sprint: "",
      due_date: "",

      blocked,
      blocker_type: blockerType,

      raw_source: "gitlab",
      source_url: webUrl,

      normalized_at: new Date().toISOString()
    }
  });
}

return normalized;

