function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function normalizePriority(priority) {
  const value = clean(priority).toLowerCase();

  if (["urgent", "critical", "critique", "1"].includes(value)) return "Critique";
  if (["high", "haute", "2"].includes(value)) return "Haute";
  if (["medium", "moyenne", "3"].includes(value)) return "Moyenne";
  if (["low", "basse", "4"].includes(value)) return "Basse";

  return priority || "Non définie";
}

function daysSince(dateValue) {
  if (!dateValue) return null;
  const date = new Date(dateValue);
  if (isNaN(date.getTime())) return null;
  return Math.floor((Date.now() - date.getTime()) / (1000 * 60 * 60 * 24));
}

function detectBlocked(issue) {
  const title = clean(issue.title).toLowerCase();
  const description = clean(issue.description).toLowerCase();
  const state = clean(issue.state?.name || issue.status || issue.state).toLowerCase();
  const labels = Array.isArray(issue.labels?.nodes)
    ? issue.labels.nodes.map(l => l.name).join(" ").toLowerCase()
    : "";

  const text = `${title} ${description} ${state} ${labels}`;

  return (
    text.includes("blocked") ||
    text.includes("bloqué") ||
    text.includes("bloquee") ||
    text.includes("bloquée") ||
    text.includes("en attente") ||
    text.includes("waiting")
  );
}

function detectBlockerType(issue) {
  const title = clean(issue.title).toLowerCase();
  const description = clean(issue.description).toLowerCase();
  const text = `${title} ${description}`;

  if (text.includes("review") || text.includes("validation") || text.includes("pr")) {
    return "Validation";
  }

  if (text.includes("api") || text.includes("bug") || text.includes("tech")) {
    return "Technique";
  }

  if (text.includes("client") || text.includes("fonctionnel") || text.includes("métier")) {
    return "Fonctionnel";
  }

  if (text.includes("dependency") || text.includes("dépendance")) {
    return "Dépendance";
  }

  return "";
}

const normalized = [];

for (const item of items) {
  const issue = item.json;

  const id = clean(issue.identifier || issue.id || issue.number);
  const title = clean(issue.title);
  const description = clean(issue.description);

  const status = clean(issue.state?.name || issue.status || issue.state);
  const assignee = clean(issue.assignee?.name || issue.assignee?.displayName || issue.assignee?.email || issue.assignee);
  const project = clean(issue.project?.name || issue.project);
  const team = clean(issue.team?.name || issue.team);

  const priorityRaw = clean(issue.priorityLabel || issue.priority);
  const priority = normalizePriority(priorityRaw);

  const createdAt = clean(issue.createdAt || issue.created_at);
  const updatedAt = clean(issue.updatedAt || issue.updated_at);
  const dueDate = clean(issue.dueDate || issue.due_date);
  const cycle = clean(issue.cycle?.name || issue.cycle);

  const ageDays = daysSince(createdAt);

  const blocked = detectBlocked(issue);
  const blockerType = detectBlockerType(issue);

  const sourceUrl = clean(issue.url || issue.webUrl);

  normalized.push({
    json: {
      source: "linear",
      type: "task",

      external_id: id,
      task_id: id,
      title,
      description,

      status,
      status_category: status,
      assignee,
      reporter: "",

      priority,
      project,
      team,
      sprint: cycle,

      created_at: createdAt,
      updated_at: updatedAt,
      due_date: dueDate,
      age_days: ageDays,

      blocked,
      blocker_type: blockerType,

      review_status: "",
      ci_status: "",
      linked_pr: "",

      raw_source: "linear",
      source_url: sourceUrl,

      normalized_at: new Date().toISOString()
    }
  });
}

return normalized;

const items = $input.all();

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function extractTaskIdFromText(text) {
  const value = clean(text);

  const patterns = [
    /([A-Z]+-\d+)/,
    /(US[-_ ]?\d+)/i,
    /(TASK[-_ ]?\d+)/i
  ];

  for (const pattern of patterns) {
    const match = value.match(pattern);
    if (match) {
      return match[1]
        .toUpperCase()
        .replace(" ", "-")
        .replace("_", "-");
    }
  }

  return "";
}

const allData = items.map(item => item.json);

const tasks = allData.filter(item => item.type === "task");
const pullRequests = allData.filter(item =>
  item.type === "pull_request" || item.type === "merge_request"
);

const prsByTaskId = {};

for (const pr of pullRequests) {
  let linkedTask = clean(pr.task_id || pr.linked_task || pr.linked_pr);

  if (!linkedTask) {
    linkedTask = extractTaskIdFromText(`${pr.title || ""} ${pr.description || ""} ${pr.source_branch || ""}`);
  }

  if (!linkedTask) continue;

  if (!prsByTaskId[linkedTask]) {
    prsByTaskId[linkedTask] = [];
  }

  prsByTaskId[linkedTask].push(pr);
}

const output = [];

for (const task of tasks) {
  const taskId = clean(task.task_id || task.external_id);
  const linkedPrs = prsByTaskId[taskId] || [];

  const hasLinkedPr = linkedPrs.length > 0;

  const blockedPrs = linkedPrs.filter(pr => pr.blocked === true);
  const waitingReviews = linkedPrs.filter(pr =>
    clean(pr.review_status).toLowerCase().includes("review") ||
    clean(pr.review_status).toLowerCase().includes("aucun reviewer")
  );

  const failedCi = linkedPrs.filter(pr =>
    clean(pr.ci_status).toLowerCase() === "failed" ||
    clean(pr.ci_status).toLowerCase() === "failure"
  );

  output.push({
    json: {
      ...task,

      linked_pr_count: linkedPrs.length,
      linked_prs: linkedPrs.map(pr => ({
        source: pr.source,
        external_id: pr.external_id,
        title: pr.title,
        status: pr.status,
        author: pr.author,
        reviewers: pr.reviewers,
        review_status: pr.review_status,
        ci_status: pr.ci_status,
        age_hours: pr.age_hours,
        blocked: pr.blocked,
        blocker_type: pr.blocker_type,
        source_url: pr.source_url
      })),

      has_linked_pr: hasLinkedPr,
      has_blocked_pr: blockedPrs.length > 0,
      has_waiting_review: waitingReviews.length > 0,
      has_failed_ci: failedCi.length > 0,

      pr_blocker_summary: blockedPrs
        .map(pr => `${pr.external_id} - ${pr.blocker_type || "Blocage PR"}`)
        .join(" | "),

      delivery_context_enriched: true,
      linked_at: new Date().toISOString()
    }
  });
}

// On garde aussi les PR/MR non liées pour ne pas perdre les signaux faibles
for (const pr of pullRequests) {
  const linkedTask = clean(pr.task_id || pr.linked_task);

  if (!linkedTask) {
    output.push({
      json: {
        ...pr,
        orphan_pr: true,
        delivery_context_enriched: true,
        linked_at: new Date().toISOString()
      }
    });
  }
}

return output;

const items = $input.all();
const today = new Date();

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function parseDate(value) {
  if (!value) return null;
  const date = new Date(value);
  return isNaN(date.getTime()) ? null : date;
}

function daysBetween(date1, date2) {
  if (!date1 || !date2) return null;
  return Math.floor((date2 - date1) / (1000 * 60 * 60 * 24));
}

function isDone(status) {
  const value = clean(status).toLowerCase();

  return (
    value.includes("done") ||
    value.includes("termin") ||
    value.includes("closed") ||
    value.includes("resolved") ||
    value.includes("livré") ||
    value.includes("livree") ||
    value.includes("livrée")
  );
}

function priorityScore(priority) {
  const value = clean(priority).toLowerCase();

  if (value.includes("critique") || value.includes("critical") || value.includes("highest")) return 20;
  if (value.includes("haute") || value.includes("high")) return 15;
  if (value.includes("moyenne") || value.includes("medium")) return 8;
  if (value.includes("basse") || value.includes("low")) return 3;

  return 5;
}

function getRiskLevel(score) {
  if (score >= 80) return "Critique";
  if (score >= 55) return "Élevé";
  if (score >= 30) return "Moyen";
  return "Faible";
}

function buildDecision(riskLevel, reasons, item) {
  const assignee = clean(item.assignee) || "responsable non identifié";

  if (riskLevel === "Critique") {
    return `Décision immédiate requise : arbitrer aujourd’hui, contacter ${assignee}, activer un backup si nécessaire et fixer une heure limite de résolution.`;
  }

  if (riskLevel === "Élevé") {
    return `Action rapide sous 24h : demander un point de blocage à ${assignee}, confirmer la cause et définir une action de déblocage.`;
  }

  if (riskLevel === "Moyen") {
    return `Surveillance renforcée : suivre l’évolution de la tâche et demander une mise à jour au prochain point projet.`;
  }

  return "Suivi normal.";
}

function detectMainRiskType(reasons) {
  const text = reasons.join(" ").toLowerCase();

  if (text.includes("review") || text.includes("validation")) return "Validation";
  if (text.includes("ci/cd")) return "Technique";
  if (text.includes("retard") || text.includes("deadline")) return "Planning";
  if (text.includes("responsable")) return "Organisation";
  if (text.includes("pr")) return "Delivery technique";
  if (text.includes("bloqué") || text.includes("bloquee")) return "Blocage";

  return "Risque delivery";
}

const risks = [];

for (const item of items) {
  const data = item.json;

  const type = clean(data.type);
  const status = clean(data.status);
  const title = clean(data.title);
  const externalId = clean(data.external_id || data.task_id || data.pr_id || data.mr_id);

  let score = 0;
  const reasons = [];

  const createdAt = parseDate(data.created_at);
  const updatedAt = parseDate(data.updated_at);
  const dueDate = parseDate(data.due_date);

  const ageDays = createdAt ? daysBetween(createdAt, today) : null;
  const inactiveDays = updatedAt ? daysBetween(updatedAt, today) : null;

  if (data.blocked === true) {
    score += 30;
    reasons.push("Élément marqué comme bloqué");
  }

  if (data.has_blocked_pr === true) {
    score += 25;
    reasons.push("PR/MR liée bloquée");
  }

  if (data.has_waiting_review === true) {
    score += 20;
    reasons.push("Review ou validation en attente");
  }

  if (data.has_failed_ci === true) {
    score += 25;
    reasons.push("CI/CD échouée sur une PR/MR liée");
  }

  if (dueDate && dueDate < today && !isDone(status)) {
    score += 25;
    reasons.push("Deadline dépassée");
  }

  if (inactiveDays !== null && inactiveDays >= 3 && !isDone(status)) {
    score += 10;
    reasons.push(`Aucune mise à jour depuis ${inactiveDays} jours`);
  }

  if (ageDays !== null && ageDays >= 5 && !isDone(status)) {
    score += 10;
    reasons.push(`Tâche ouverte depuis ${ageDays} jours`);
  }

  if (!clean(data.assignee)) {
    score += 15;
    reasons.push("Aucun responsable assigné");
  }

  if (type === "task" && clean(data.priority)) {
    const pScore = priorityScore(data.priority);
    score += pScore;

    if (pScore >= 15) {
      reasons.push("Priorité élevée");
    }
  }

  if (type === "pull_request" || type === "merge_request") {
    if (data.age_hours !== null && data.age_hours >= 24 && !isDone(status)) {
      score += 20;
      reasons.push(`PR/MR ouverte depuis ${data.age_hours} heures`);
    }

    if (clean(data.review_status).toLowerCase().includes("aucun reviewer")) {
      score += 20;
      reasons.push("Aucun reviewer assigné");
    }

    if (clean(data.ci_status).toLowerCase() === "failed") {
      score += 25;
      reasons.push("CI/CD échouée");
    }
