  const riskLevel = getRiskLevel(score);
  const riskType = detectMainRiskType(reasons);
  const decision = buildDecision(riskLevel, reasons, data);

  const alertKeyParts = [
    data.source || "unknown",
    externalId || title,
    riskType,
    riskLevel
  ];

  const alertKey = alertKeyParts
    .join("-")
    .replace(/\s+/g, "_")
    .toLowerCase();

  risks.push({
    json: {
      alert_key: alertKey,

      source: data.source,
