  executiveSummary = `Le sprint est en zone critique avec ${totalRisks} risque(s) détecté(s), dont ${criticalRisks.length} critique(s). Une décision d’arbitrage est nécessaire aujourd’hui.`;
} else if (globalRiskLevel === "Élevé") {
  executiveSummary = `Le sprint présente un niveau de risque élevé avec ${totalRisks} risque(s) détecté(s). Les blocages principaux doivent être traités sous 24h.`;
} else if (globalRiskLevel === "Moyen") {
  executiveSummary = `Le sprint reste maîtrisable mais nécessite une surveillance renforcée. ${totalRisks} risque(s) doivent être suivis.`;
} else {
