parameters.jsCode:
const items = $input.all();

for (const item of items) {
  const data = item.json;
  let decision_score = 0;

  // PR sans reviewer ou ticket haute priorité
  if ((data.type === 'pull_request' || data.type === 'merge_request') &&
      (!data.reviewers || data.reviewers.length === 0) &&
      data.priority.toLowerCase().includes('haute')) {
    decision_score = 100; // alerte critique
  }

  // PR approuvée mais non fusionnée
  if ((data.type === 'pull_request' || data.type === 'merge_request') &&
      data.status.toLowerCase() === 'approved' &&
      !data.merged_at) {
    decision_score = 50; // rappel simple
  }

  data.decision_score = decision_score;
}
return items;

